ucs.sentinel_kql:
// Molerats DropBook / SharpStage cloud-API C2 — Sentinel via ASIM web-session telemetry (proxy / EDR connector)
let _legit_clients = dynamic(["chrome.exe","msedge.exe","firefox.exe","brave.exe","opera.exe","iexplore.exe","outlook.exe","teams.exe","onedrive.exe","dropbox.exe","googledrivesync.exe","msedgewebview2.exe","slack.exe","explorer.exe","winword.exe","excel.exe","powerpnt.exe"]);
let _c2_hosts = dynamic(["api.dropbox.com","content.dropboxapi.com","api.dropboxapi.com","www.googleapis.com","oauth2.googleapis.com","graph.facebook.com","www.facebook.com"]);
ImWebSession
| where TimeGenerated > ago(7d)
| where HttpHostName in~ (_c2_hosts) or HttpHostName endswith ".dropboxusercontent.com"
| extend ProcessName = tolower(tostring(parse_json(tostring(AdditionalFields)).ActingProcessName))
| where isempty(ProcessName) or ProcessName !in~ (_legit_clients)
| project TimeGenerated, DvcHostname, SrcUsername, ProcessName, Url, HttpHostName, HttpMethod, DstIpAddr, HttpRequestHeaderUserAgent
| order by TimeGenerated desc
